async function getImage(query) {
    return new Promise((resolve) => {
        const url = `https://duckduckgo.com/i.js?q=${encodeURIComponent(query)}&o=json`;

        const req = https.get(url, {
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
                'Accept': 'application/json'
            }
        }, (res) => {
            let data = '';
            res.on('data', chunk => data += chunk);
            res.on('end', () => {
                try {
                    const json = JSON.parse(data);
                    if (json.results && json.results.length > 0) {
                        resolve(json.results[0].image);
                    } else {
                        resolve(null);
                    }
                } catch (e) {
                    resolve(null);
                }
            });
        });

        req.on('error', () => resolve(null));
        req.end();
    });
}
// This needs vqd token to work on DDG. Let's instead use unsplash proxy or Wikimedia or Pixabay.

import { useState, useRef, useEffect } from 'react'
import { products } from '../data/products'

// Build product context for AI
const PRODUCT_CONTEXT = products.map(p =>
    `[${p.id}] ${p.name} | Category: ${p.cat} | Price: ₹${p.price.toLocaleString('en-IN')} | Rating: ${p.rating}/5 | ${p.rev.toLocaleString()} reviews | ${p.badge || ''} | ${p.desc}`
).join('\n')

const SYSTEM_PROMPT = `You are ShopBot, a helpful shopping assistant for Shop Smart — an Indian e-commerce platform.
You ONLY answer questions about the products listed below. Be concise, friendly, and use emojis occasionally.
If asked about something outside the product catalog, politely say you can only help with Shop Smart products.

PRODUCT CATALOG:
${PRODUCT_CONTEXT}

Guidelines:
- Recommend products based on budget, category, or use case
- Compare products when asked
- Mention prices in Indian Rupees (₹)
- Mention ratings and reviews to support recommendations
- Keep responses under 150 words unless comparing multiple products
- If user asks to add to cart, say they can click "Add to Cart" on the product page`

const QUICK_QUESTIONS = [
    '🔥 What are the best sellers?',
    '📱 Best phone under ₹50,000?',
    '💪 Fitness products?',
    '📚 Book recommendations?',
    '👗 Fashion under ₹3,000?',
]

export default function Chatbot() {
    const [open, setOpen] = useState(false)
    const [messages, setMessages] = useState([
        { role: 'assistant', text: "Hi! I'm ShopBot 🤖 Ask me anything about our products — prices, recommendations, comparisons, and more!" }
    ])
    const [input, setInput] = useState('')
    const [loading, setLoading] = useState(false)
    const [apiKey, setApiKey] = useState(localStorage.getItem('geminiKey') || '')
    const [showKeyInput, setShowKeyInput] = useState(false)
    const [unread, setUnread] = useState(0)
    const bottomRef = useRef()
    const inputRef = useRef()

    useEffect(() => {
        bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
    }, [messages, loading])

    useEffect(() => {
        if (!open && messages.length > 1) setUnread(u => u + 1)
    }, [messages])

    const saveKey = () => {
        localStorage.setItem('geminiKey', apiKey)
        setShowKeyInput(false)
    }

    const sendMessage = async (text) => {
        const q = text || input.trim()
        if (!q) return
        if (!apiKey) { setShowKeyInput(true); return }

        setMessages(prev => [...prev, { role: 'user', text: q }])
        setInput('')
        setLoading(true)

        try {
            const history = messages.slice(1).map(m => ({
                role: m.role === 'assistant' ? 'model' : 'user',
                parts: [{ text: m.text }]
            }))

            const res = await fetch(
                `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${apiKey}`,
                {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        system_instruction: { parts: [{ text: SYSTEM_PROMPT }] },
                        contents: [
                            ...history,
                            { role: 'user', parts: [{ text: q }] }
                        ],
                        generationConfig: { maxOutputTokens: 512, temperature: 0.7 }
                    })
                }
            )

            const data = await res.json()
            if (data.error) throw new Error(data.error.message)
            const reply = data.candidates?.[0]?.content?.parts?.[0]?.text || 'Sorry, I could not understand that. Try again!'
            setMessages(prev => [...prev, { role: 'assistant', text: reply }])
        } catch (e) {
            setMessages(prev => [...prev, { role: 'assistant', text: `❌ Error: ${e.message}. Please check your Gemini API key.` }])
        }
        setLoading(false)
    }

    return (
        <>
            {/* Floating Button */}
            <button
                onClick={() => { setOpen(o => !o); setUnread(0) }}
                className="fixed bottom-20 md:bottom-6 right-4 z-[8000] bg-gradient-to-br from-violet-600 to-purple-700 text-white w-14 h-14 rounded-full shadow-2xl flex items-center justify-center text-2xl transition-all duration-300 hover:scale-110 hover:shadow-purple-400/40"
                title="ShopBot AI Assistant">
                {open ? '✕' : '🤖'}
                {!open && unread > 0 && (
                    <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs font-black rounded-full w-5 h-5 flex items-center justify-center animate-pulse">{unread}</span>
                )}
            </button>

            {/* Chat Window */}
            {open && (
                <div className="fixed bottom-36 md:bottom-24 right-4 z-[8000] w-80 sm:w-96 bg-white dark:bg-gray-900 rounded-2xl shadow-2xl border border-gray-200 dark:border-gray-700 flex flex-col overflow-hidden animate-slide-up" style={{ maxHeight: '480px' }}>
                    {/* Header */}
                    <div className="bg-gradient-to-r from-violet-600 to-purple-700 text-white px-4 py-3 flex items-center gap-3">
                        <div className="w-9 h-9 bg-white/20 rounded-full flex items-center justify-center text-lg">🤖</div>
                        <div className="flex-1">
                            <p className="font-extrabold text-sm">ShopBot</p>
                            <p className="text-xs text-purple-200">AI Shopping Assistant</p>
                        </div>
                        <button onClick={() => setShowKeyInput(s => !s)} title="Set API Key" className="bg-white/10 hover:bg-white/20 px-2 py-1 rounded-lg text-xs transition-colors">⚙️ Key</button>
                    </div>

                    {/* API Key Input */}
                    {showKeyInput && (
                        <div className="bg-purple-50 dark:bg-purple-900/20 border-b border-purple-200 dark:border-purple-800 p-3">
                            <p className="text-xs font-bold text-purple-700 dark:text-purple-300 mb-2">🔑 Gemini API Key</p>
                            <div className="flex gap-2">
                                <input type="password" value={apiKey} onChange={e => setApiKey(e.target.value)}
                                    placeholder="AIzaSy..." className="flex-1 px-3 py-1.5 text-xs border border-purple-300 dark:border-purple-600 rounded-lg bg-white dark:bg-gray-800 outline-none focus:border-purple-500" />
                                <button onClick={saveKey} className="bg-purple-600 text-white px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-purple-700">Save</button>
                            </div>
                            <p className="text-[10px] text-purple-500 mt-1">Get free key at <a href="https://aistudio.google.com/" target="_blank" rel="noreferrer" className="underline">aistudio.google.com</a></p>
                        </div>
                    )}

                    {/* Messages */}
                    <div className="flex-1 overflow-y-auto p-4 space-y-3" style={{ minHeight: '200px', maxHeight: '280px' }}>
                        {messages.map((m, i) => (
                            <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[85%] px-3 py-2 rounded-2xl text-sm leading-relaxed ${m.role === 'user'
                                        ? 'bg-violet-600 text-white rounded-br-sm'
                                        : 'bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-200 rounded-bl-sm'
                                    }`}>
                                    {m.text}
                                </div>
                            </div>
                        ))}
                        {loading && (
                            <div className="flex justify-start">
                                <div className="bg-gray-100 dark:bg-gray-700 px-4 py-3 rounded-2xl rounded-bl-sm flex gap-1">
                                    {[0, 1, 2].map(i => (
                                        <span key={i} className="w-2 h-2 bg-gray-400 rounded-full animate-bounce" style={{ animationDelay: `${i * 0.15}s` }} />
                                    ))}
                                </div>
                            </div>
                        )}
                        <div ref={bottomRef} />
                    </div>

                    {/* Quick Questions */}
                    {messages.length <= 1 && (
                        <div className="px-3 pb-2 flex gap-2 overflow-x-auto scrollbar-hide">
                            {QUICK_QUESTIONS.map(q => (
                                <button key={q} onClick={() => sendMessage(q)}
                                    className="flex-shrink-0 text-xs bg-purple-50 dark:bg-purple-900/30 text-purple-700 dark:text-purple-300 border border-purple-200 dark:border-purple-700 px-3 py-1.5 rounded-full hover:bg-purple-100 transition-colors whitespace-nowrap">
                                    {q}
                                </button>
                            ))}
                        </div>
                    )}

                    {/* Input */}
                    <div className="border-t border-gray-200 dark:border-gray-700 p-3 flex gap-2">
                        <input
                            ref={inputRef} type="text" value={input}
                            onChange={e => setInput(e.target.value)}
                            onKeyDown={e => e.key === 'Enter' && !loading && sendMessage()}
                            placeholder={apiKey ? 'Ask about any product...' : 'Set API key first (⚙️ Key)'}
                            className="flex-1 px-3 py-2 text-sm border border-gray-200 dark:border-gray-600 rounded-xl bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100 outline-none focus:border-violet-500 transition-colors"
                        />
                        <button onClick={() => sendMessage()} disabled={loading || !input.trim()}
                            className="bg-violet-600 hover:bg-violet-700 disabled:opacity-50 text-white px-4 py-2 rounded-xl text-sm font-bold transition-all">
                            {loading ? '⏳' : '➤'}
                        </button>
                    </div>
                </div>
            )}
        </>
    )
}

import { useState, useRef, useEffect } from 'react'
import { Link, useNavigate, useLocation } from 'react-router-dom'
import { useCart } from '../context/CartContext'
import { useWishlist } from '../context/WishlistContext'
import { useAuth } from '../context/AuthContext'
import { useTheme } from '../context/ThemeContext'
import { useCurrency } from '../context/CurrencyContext'
import { products, toSlug } from '../data/products'

const CATEGORIES = [
    { label: 'Home', path: '/', icon: '🏠' },
    { label: 'Electronics', path: '/electronics', icon: '📱' },
    { label: 'Fashion', path: '/fashion', icon: '👔' },
    { label: 'Home & Living', path: '/home', icon: '🏡' },
    { label: 'Sports', path: '/sports', icon: '⚽' },
    { label: 'Beauty', path: '/beauty', icon: '💄' },
    { label: 'Books', path: '/books', icon: '📚' },
    { label: 'Compare', path: '/compare', icon: '⚖️' },
    { label: 'Orders', path: '/orders', icon: '📦' },
]

export default function Navbar() {
    const { cartCount } = useCart()
    const { wishlistCount } = useWishlist()
    const { user, logout } = useAuth()
    const { dark, toggleTheme } = useTheme()
    const { currency, changeCurrency, CURRENCIES } = useCurrency()

    const [query, setQuery] = useState('')
    const [suggestions, setSuggestions] = useState([])
    const [showSugg, setShowSugg] = useState(false)
    const [menuOpen, setMenuOpen] = useState(false)
    const [mobileMenu, setMobileMenu] = useState(false)

    const navigate = useNavigate()
    const location = useLocation()
    const searchRef = useRef()
    const menuRef = useRef()

    // Close search on outside click
    useEffect(() => {
        const h = e => { if (!searchRef.current?.contains(e.target)) setShowSugg(false) }
        document.addEventListener('mousedown', h)
        return () => document.removeEventListener('mousedown', h)
    }, [])

    // Close account menu on outside click
    useEffect(() => {
        const h = e => { if (!menuRef.current?.contains(e.target)) setMenuOpen(false) }
        document.addEventListener('mousedown', h)
        return () => document.removeEventListener('mousedown', h)
    }, [])

    // Close all menus on route change
    useEffect(() => { setMenuOpen(false); setMobileMenu(false) }, [location.pathname])

    const handleSearch = q => {
        if (!q.trim()) return
        const recent = JSON.parse(localStorage.getItem('recentSearches') || '[]')
        localStorage.setItem('recentSearches', JSON.stringify([q, ...recent.filter(s => s !== q)].slice(0, 5)))
        navigate(`/search?q=${encodeURIComponent(q)}`)
        setShowSugg(false); setQuery('')
    }

    const handleInput = v => {
        setQuery(v)
        if (v.length > 1) {
            const lv = v.toLowerCase()
            setSuggestions(products.filter(p =>
                p.name.toLowerCase().includes(lv) ||
                (p.tags && p.tags.toLowerCase().includes(lv)) ||
                p.desc.toLowerCase().includes(lv)
            ).slice(0, 6))
            setShowSugg(true)
        } else {
            const recent = JSON.parse(localStorage.getItem('recentSearches') || '[]')
            setSuggestions([]); setShowSugg(recent.length > 0)
        }
    }

    const recentSearches = JSON.parse(localStorage.getItem('recentSearches') || '[]')

    return (
        <>
            {/* ── MAIN NAVBAR + CATEGORY BAR wrapped in one sticky block ── */}
            <div className="sticky top-0 z-50 shadow-xl">
                <nav className="bg-gray-900 text-white">

                    {/* 3-column grid: [logo] [search center] [icons] */}
                    <div className="max-w-7xl mx-auto px-4 h-14 grid grid-cols-[auto_1fr_auto] items-center gap-4">

                        {/* ── LEFT: hamburger + logo ── */}
                        <div className="flex items-center gap-2">
                            <button className="lg:hidden flex flex-col justify-center gap-1 w-6 h-6"
                                onClick={() => setMobileMenu(o => !o)} aria-label="Menu">
                                <span className={`block h-0.5 bg-white rounded transition-all duration-300 origin-center ${mobileMenu ? 'rotate-45 translate-y-[6px]' : ''}`} />
                                <span className={`block h-0.5 bg-white rounded transition-all duration-200 ${mobileMenu ? 'opacity-0 scale-x-0' : ''}`} />
                                <span className={`block h-0.5 bg-white rounded transition-all duration-300 origin-center ${mobileMenu ? '-rotate-45 -translate-y-[6px]' : ''}`} />
                            </button>
                            <Link to="/" className="text-base font-extrabold tracking-tight whitespace-nowrap">
                                Shop<span className="text-amber-400">Smart</span>
                            </Link>
                        </div>

                        {/* ── CENTER: search bar ── */}
                        <div className="hidden sm:flex justify-center">
                            <div className="relative w-full max-w-xs" ref={searchRef}>
                                <div className="flex rounded-lg overflow-hidden border border-white/15 focus-within:border-amber-400/70 transition-colors">
                                    <input
                                        type="text" value={query}
                                        placeholder="Search products..."
                                        className="w-full px-3 py-1.5 bg-white/10 text-white placeholder-white/40 outline-none text-sm"
                                        onChange={e => handleInput(e.target.value)}
                                        onFocus={() => { if (!query) setShowSugg(recentSearches.length > 0) }}
                                        onKeyDown={e => e.key === 'Enter' && handleSearch(query)}
                                    />
                                    <button onClick={() => handleSearch(query)}
                                        className="bg-amber-400 hover:bg-amber-500 px-3 text-gray-900 font-bold text-sm transition-colors flex-shrink-0">
                                        🔍
                                    </button>
                                </div>

                                {/* Autocomplete dropdown */}
                                {showSugg && (
                                    <div className="absolute top-full left-0 right-0 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg mt-1 shadow-2xl z-[999] overflow-hidden">
                                        {suggestions.length > 0 ? suggestions.map(p => (
                                            <div key={p.id}
                                                className="px-3 py-2 hover:bg-gray-50 dark:hover:bg-gray-700 cursor-pointer flex items-center gap-3"
                                                onClick={() => { navigate(`/product/${toSlug(p.name)}`); setShowSugg(false); setQuery('') }}>
                                                <img src={p.img} alt={p.name} className="w-8 h-8 rounded object-cover flex-shrink-0" />
                                                <span className="text-sm text-gray-800 dark:text-gray-200 flex-1 truncate">{p.name}</span>
                                                <span className="text-xs text-amber-500 font-bold flex-shrink-0">₹{p.price.toLocaleString('en-IN')}</span>
                                            </div>
                                        )) : recentSearches.length > 0 && (
                                            <div>
                                                <p className="text-xs text-gray-400 px-4 py-2 border-b border-gray-100 dark:border-gray-700">Recent Searches</p>
                                                {recentSearches.map(s => (
                                                    <div key={s}
                                                        className="px-4 py-2 hover:bg-gray-50 dark:hover:bg-gray-700 cursor-pointer text-sm text-gray-700 dark:text-gray-300 flex items-center gap-2"
                                                        onClick={() => { setQuery(s); handleSearch(s) }}>
                                                        🕒 {s}
                                                    </div>
                                                ))}
                                                <button className="w-full text-right px-4 py-2 text-xs text-amber-500 border-t border-gray-100 dark:border-gray-700"
                                                    onClick={() => { localStorage.removeItem('recentSearches'); setShowSugg(false) }}>
                                                    Clear all
                                                </button>
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* ── RIGHT: icon buttons ── */}
                        <div className="flex items-center gap-1">
                            {/* Currency */}
                            <select value={currency} onChange={e => changeCurrency(e.target.value)}
                                className="hidden lg:block bg-transparent text-white text-xs font-semibold px-1.5 py-1.5 rounded-lg border border-white/20 outline-none cursor-pointer hover:bg-white/10 transition-colors">
                                {Object.entries(CURRENCIES).map(([code, c]) => (
                                    <option key={code} value={code} className="bg-gray-800 text-white">{c.flag} {code}</option>
                                ))}
                            </select>

                            {/* Dark mode */}
                            <button onClick={toggleTheme}
                                className="hover:bg-white/10 p-2 rounded-lg text-base transition-colors" title="Toggle Theme">
                                {dark ? '☀️' : '🌙'}
                            </button>

                            {/* Wishlist */}
                            <Link to="/wishlist" className="relative hover:bg-white/10 p-2 rounded-lg transition-colors">
                                <span className="text-base">❤️</span>
                                {wishlistCount > 0 && (
                                    <span className="absolute top-0.5 right-0.5 bg-amber-400 text-gray-900 text-[10px] font-black rounded-full w-4 h-4 flex items-center justify-center">
                                        {wishlistCount}
                                    </span>
                                )}
                            </Link>

                            {/* Cart */}
                            <Link to="/cart" className="relative hover:bg-white/10 p-2 rounded-lg transition-colors">
                                <span className="text-base">🛒</span>
                                {cartCount > 0 && (
                                    <span className="absolute top-0.5 right-0.5 bg-amber-400 text-gray-900 text-[10px] font-black rounded-full w-4 h-4 flex items-center justify-center">
                                        {cartCount}
                                    </span>
                                )}
                            </Link>

                            {/* Account dropdown */}
                            <div className="relative" ref={menuRef}>
                                <button onClick={() => setMenuOpen(o => !o)}
                                    className="hover:bg-white/10 px-2 py-2 rounded-lg text-sm transition-colors flex items-center gap-1">
                                    <span>👤</span>
                                    <span className="hidden md:block text-xs max-w-[60px] truncate">
                                        {user ? user.name?.split(' ')[0] : 'Account'}
                                    </span>
                                    <span className="hidden md:block text-white/40 text-xs">▾</span>
                                </button>

                                {menuOpen && (
                                    <div className="absolute right-0 top-full mt-2 w-52 bg-white dark:bg-gray-800 rounded-xl shadow-2xl border border-gray-100 dark:border-gray-700 overflow-hidden z-[200]">
                                        {user ? (
                                            <>
                                                <div className="px-4 py-3 bg-gradient-to-r from-amber-50 to-orange-50 dark:from-gray-700 dark:to-gray-700 border-b border-gray-100 dark:border-gray-600">
                                                    <p className="font-bold text-gray-900 dark:text-white text-sm truncate">{user.name}</p>
                                                    <p className="text-xs text-gray-500 dark:text-gray-400 truncate">{user.email}</p>
                                                </div>
                                                <Link to="/orders" onClick={() => setMenuOpen(false)} className="flex items-center gap-3 px-4 py-2.5 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700">📦 My Orders</Link>
                                                <Link to="/wishlist" onClick={() => setMenuOpen(false)} className="flex items-center gap-3 px-4 py-2.5 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700">❤️ Wishlist</Link>
                                                <Link to="/admin" onClick={() => setMenuOpen(false)} className="flex items-center gap-3 px-4 py-2.5 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700">⚙️ Admin Panel</Link>
                                                <button onClick={() => { logout(); setMenuOpen(false) }}
                                                    className="w-full flex items-center gap-3 px-4 py-2.5 text-sm text-red-500 hover:bg-red-50 dark:hover:bg-gray-700 border-t border-gray-100 dark:border-gray-600">
                                                    🚪 Logout
                                                </button>
                                            </>
                                        ) : (
                                            <>
                                                <Link to="/login" onClick={() => setMenuOpen(false)} className="flex items-center gap-3 px-4 py-3 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700 font-semibold">🔑 Login</Link>
