    const stockLevel = (() => {
        const levels = { 1: 3, 3: 1, 5: 8, 7: 2, 9: 15, 11: 5, 13: 0, 15: 20 }
        return levels[product.id] ?? (product.id % 10) + 5
    })()

    return (
        <div className="card group flex flex-col relative">
