                <button onClick={handleAddToCart} disabled={adding || stockLevel === 0}
                    className={`w-full py-2.5 rounded-lg font-bold text-sm transition-all duration-200 ${stockLevel === 0 ? 'bg-gray-200 text-gray-400 cursor-not-allowed dark:bg-gray-700' : adding ? 'bg-green-500 text-white scale-95' : 'bg-amber-400 hover:bg-amber-500 text-gray-900 hover:shadow-lg hover:-translate-y-0.5'}`}>
