                <p className="text-gray-400 text-sm mb-6">Enter admin password to continue</p>
                {authErr && <p className="text-red-400 text-sm mb-3">{authErr}</p>}
                <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password"
                    onKeyDown={e => e.key === 'Enter' && signIn()}
                    className="w-full px-4 py-3 bg-gray-800 border border-gray-600 rounded-xl text-white outline-none focus:border-amber-400 mb-4" />
                <button onClick={signIn} className="w-full bg-amber-400 hover:bg-amber-500 text-gray-900 font-extrabold py-3 rounded-xl transition-colors">
                    Sign In →
                </button>
                <p className="text-xs text-gray-500 mt-4">Demo password: <code className="text-amber-400">admin123</code></p>
            </div>
        </div>
    )

    return (
        <div className="min-h-screen bg-gray-100 dark:bg-gray-950">
            {/* Admin Header */}
            <div className="bg-gray-900 text-white px-6 py-4 flex items-center justify-between shadow-xl">
                <div className="flex items-center gap-3">
                    <span className="text-2xl">⚙️</span>
                    <div>
                        <h1 className="font-extrabold text-lg">Shop Smart Admin</h1>
                        <p className="text-gray-400 text-xs">Management Dashboard</p>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <button onClick={() => navigate('/')} className="text-sm text-gray-400 hover:text-white transition-colors">← View Site</button>
                    <button onClick={() => { sessionStorage.removeItem('adminAuthed'); setAuthed(false) }} className="bg-red-500/20 hover:bg-red-500/40 text-red-400 px-4 py-2 rounded-lg text-sm font-semibold transition-colors">Logout</button>
                </div>
            </div>

            <div className="max-w-7xl mx-auto px-4 py-8">
                {/* Stats */}
                <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
                    {STATS.map(s => (
                        <div key={s.label} className={`bg-gradient-to-br ${s.color} rounded-2xl p-5 text-white shadow-lg`}>
                            <div className="text-3xl mb-2">{s.icon}</div>
                            <div className="text-2xl font-extrabold">{s.value}</div>
                            <div className="text-sm opacity-80 mt-1">{s.label}</div>
                        </div>
                    ))}
                </div>

                {/* Tabs */}
                <div className="flex gap-2 mb-6 bg-white dark:bg-gray-800 rounded-xl p-1.5 border border-gray-200 dark:border-gray-700 w-fit shadow-sm">
                    {[['📦 Products', 'products'], ['🛒 Orders', 'orders']].map(([label, tab]) => (
                        <button key={tab} onClick={() => setActiveTab(tab)}
                            className={`px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === tab ? 'bg-amber-400 text-gray-900' : 'text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white'}`}>
                            {label}
                        </button>
                    ))}
                </div>

                {/* Products Tab */}
                {activeTab === 'products' && (
                    <div>
                        {/* Toolbar */}
                        <div className="flex flex-wrap gap-3 items-center justify-between mb-5">
                            <div className="flex gap-3 flex-wrap">
                                <input type="text" value={searchQ} onChange={e => setSearchQ(e.target.value)}
                                    placeholder="Search products..." className="px-4 py-2.5 border border-gray-200 dark:border-gray-600 rounded-xl text-sm bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100 outline-none focus:border-amber-400 min-w-[200px]" />
                                <select value={filterCat} onChange={e => setFilterCat(e.target.value)} className="px-4 py-2.5 border border-gray-200 dark:border-gray-600 rounded-xl text-sm bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-200 outline-none focus:border-amber-400">
                                    <option value="all">All Categories</option>
                                    {Object.entries(CATEGORY_META).map(([k, v]) => <option key={k} value={k}>{v.icon} {v.name}</option>)}
                                </select>
                                <span className="text-sm text-gray-400 self-center">{filtered.length} products</span>
                            </div>
                            <button onClick={openAdd} className="bg-amber-400 hover:bg-amber-500 text-gray-900 font-bold px-5 py-2.5 rounded-xl text-sm transition-colors shadow-md">
                                + Add Product
                            </button>
                        </div>

                        {/* Products Table */}
                        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden">
                            <div className="overflow-x-auto">
                                <table className="w-full text-sm">
                                    <thead className="bg-gray-50 dark:bg-gray-700/50 border-b border-gray-200 dark:border-gray-700">
                                        <tr>
                                            {['Image', 'Name', 'Category', 'Price', 'Rating', 'Badge', 'Actions'].map(h => (
                                                <th key={h} className="py-3.5 px-4 text-left text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider">{h}</th>
                                            ))}
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                                        {filtered.map(p => (
                                            <tr key={p.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/30 transition-colors">
                                                <td className="py-3 px-4">
                                                    <img src={p.img} alt={p.name} className="w-12 h-12 rounded-xl object-cover" onError={e => { e.target.style.display = 'none' }} />
                                                </td>
                                                <td className="py-3 px-4"><p className="font-semibold text-gray-900 dark:text-white max-w-[200px] truncate">{p.name}</p></td>
                                                <td className="py-3 px-4"><span className="text-xs bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 px-2 py-1 rounded-full">{CATEGORY_META[p.cat]?.icon} {p.cat}</span></td>
                                                <td className="py-3 px-4 font-bold text-amber-500">{formatPrice(p.price)}</td>
                                                <td className="py-3 px-4">⭐ {p.rating}</td>
                                                <td className="py-3 px-4">
                                                    {p.badge && <span className={`text-xs px-2 py-1 rounded-full font-bold ${p.badge === 'Best Seller' ? 'bg-green-100 text-green-700' : p.badge === 'Sale' ? 'bg-red-100 text-red-700' : p.badge === 'Hot' ? 'bg-orange-100 text-orange-700' : 'bg-blue-100 text-blue-700'}`}>{p.badge}</span>}
                                                </td>
                                                <td className="py-3 px-4">
                                                    <div className="flex gap-2">
                                                        <button onClick={() => openEdit(p)} className="bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-blue-100 transition-colors">Edit</button>
                                                        <button onClick={() => deleteProduct(p.id)} className="bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400 px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-red-100 transition-colors">Delete</button>
                                                    </div>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>
                )}

                {/* Orders Tab */}
                {activeTab === 'orders' && (
                    <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden">
                        {orders.length === 0 ? (
                            <div className="py-20 text-center text-gray-400">
                                <div className="text-5xl mb-4">📭</div>
                                <p className="text-lg font-semibold">No orders yet</p>
                            </div>
                        ) : (
                            <div className="overflow-x-auto">
                                <table className="w-full text-sm">
                                    <thead className="bg-gray-50 dark:bg-gray-700/50 border-b border-gray-200 dark:border-gray-700">
                                        <tr>
                                            {['Order ID', 'Customer', 'Items', 'Total', 'Payment', 'Status'].map(h => (
                                                <th key={h} className="py-3.5 px-4 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">{h}</th>
                                            ))}
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                                        {orders.map((o, i) => (
                                            <tr key={i} className="hover:bg-gray-50 dark:hover:bg-gray-700/30 transition-colors">
                                                <td className="py-3 px-4 font-mono text-xs font-bold text-gray-600 dark:text-gray-400">{o.id || `SS${1000 + i}`}</td>
                                                <td className="py-3 px-4">
                                                    <p className="font-semibold text-gray-900 dark:text-white">{o.address?.name || 'Guest'}</p>
                                                    <p className="text-xs text-gray-400">{o.userId}</p>
                                                </td>
                                                <td className="py-3 px-4 text-gray-600 dark:text-gray-400">{o.items?.length || 0} item(s)</td>
                                                <td className="py-3 px-4 font-bold text-amber-500">₹{(o.total || 0).toLocaleString('en-IN')}</td>
                                                <td className="py-3 px-4 text-gray-500 capitalize text-xs">{o.paymentMethod || 'COD'}</td>
                                                <td className="py-3 px-4">
                                                    <select className="text-xs bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-400 font-bold px-2 py-1 rounded-full border-none outline-none cursor-pointer">
                                                        {['Processing', 'Shipped', 'Delivered', 'Cancelled'].map(s => <option key={s}>{s}</option>)}
                                                    </select>
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>
                )}

                {/* Add/Edit Form Modal */}
                {showForm && (
                    <div className="fixed inset-0 bg-black/70 backdrop-blur-sm z-50 flex items-center justify-center p-4" onClick={() => setShowForm(false)}>
                        <div className="bg-white dark:bg-gray-800 rounded-2xl w-full max-w-lg shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
                            <div className="bg-gray-900 text-white px-6 py-4 flex items-center justify-between">
                                <h2 className="font-extrabold text-lg">{editProduct ? '✏️ Edit Product' : '➕ Add Product'}</h2>
                                <button onClick={() => setShowForm(false)} className="text-gray-400 hover:text-white text-xl">✕</button>
                            </div>
                            <div className="p-6 space-y-4 max-h-[70vh] overflow-y-auto">
                                {[['Product Name', 'name', 'text'], ['Price (₹)', 'price', 'number'], ['Original Price (₹)', 'orig', 'number'], ['Description', 'desc', 'text']].map(([label, key, type]) => (
                                    <div key={key}>
                                        <label className="block text-xs font-bold text-gray-500 dark:text-gray-400 mb-1.5 uppercase tracking-wide">{label}</label>
                                        <input type={type} value={formData[key]} onChange={e => setFormData(f => ({ ...f, [key]: e.target.value }))}
                                            className="w-full px-4 py-2.5 border border-gray-200 dark:border-gray-600 rounded-xl bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 outline-none focus:border-amber-400 text-sm" />
                                    </div>
                                ))}
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase tracking-wide">Category</label>
                                        <select value={formData.cat} onChange={e => setFormData(f => ({ ...f, cat: e.target.value }))}
                                            className="w-full px-3 py-2.5 border border-gray-200 dark:border-gray-600 rounded-xl bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 outline-none text-sm">
                                            {Object.entries(CATEGORY_META).map(([k, v]) => <option key={k} value={k}>{v.name}</option>)}
                                        </select>
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase tracking-wide">Badge</label>
                                        <select value={formData.badge} onChange={e => setFormData(f => ({ ...f, badge: e.target.value }))}
                                            className="w-full px-3 py-2.5 border border-gray-200 dark:border-gray-600 rounded-xl bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 outline-none text-sm">
                                            <option value="">None</option>
                                            {['Best Seller', 'Sale', 'Hot', 'New'].map(b => <option key={b}>{b}</option>)}
                                        </select>
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-gray-500 mb-1.5 uppercase tracking-wide">Image URL</label>
                                    <input value={formData.img} onChange={e => setFormData(f => ({ ...f, img: e.target.value }))}
                                        className="w-full px-4 py-2.5 border border-gray-200 dark:border-gray-600 rounded-xl bg-white dark:bg-gray-700 text-gray-900 dark:text-gray-100 outline-none focus:border-amber-400 text-sm" placeholder="https://..." />
                                    {formData.img && <img src={formData.img} alt="preview" className="mt-2 h-20 object-cover rounded-xl" onError={e => { e.target.style.display = 'none' }} />}
                                </div>
                                <div className="flex gap-3 pt-2">
                                    <button onClick={saveForm} className="flex-1 bg-amber-400 hover:bg-amber-500 text-gray-900 font-extrabold py-3 rounded-xl transition-colors">
                                        {editProduct ? '💾 Save Changes' : '✅ Add Product'}
                                    </button>
                                    <button onClick={() => setShowForm(false)} className="px-5 py-3 border border-gray-200 dark:border-gray-600 rounded-xl text-gray-600 dark:text-gray-400 font-semibold hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors">Cancel</button>
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    )
}

import { useState, useMemo } from 'react'
import { useParams, Link } from 'react-router-dom'
import ProductCard from '../components/ProductCard'
import QuickViewModal from '../components/QuickViewModal'
import { products, CATEGORY_META } from '../data/products'
import { useCurrency } from '../context/CurrencyContext'
import { useNotification } from '../components/Notification'
import usePageTitle from '../hooks/usePageTitle'

const FILTERS = ['All', '🏷️ Sale', '✨ New', '⭐ Popular']
const SORTS = [
    { label: 'Featured', value: 'default' },
    { label: 'Price: Low–High', value: 'price-low' },
    { label: 'Price: High–Low', value: 'price-high' },
    { label: 'Top Rated', value: 'rating' },
    { label: 'Most Reviews', value: 'reviews' },
]

export default function Category() {
    const { category } = useParams()
    const cat = CATEGORY_META[category]
    usePageTitle(cat ? cat.name : 'Category')
    const { formatPrice } = useCurrency()
    const [filter, setFilter] = useState('All')
    const [sort, setSort] = useState('default')
    const [priceMax, setPriceMax] = useState(null)
    const [quickProduct, setQuickProduct] = useState(null)
    const [compareList, setCompareList] = useState([])
    const { notify } = useNotification()

    const catProducts = products.filter(p => p.cat === category)
    const maxPrice = Math.max(...catProducts.map(p => p.price))
    const effectiveMax = priceMax ?? maxPrice

    const filtered = useMemo(() => {
        let list = [...catProducts].filter(p => p.price <= effectiveMax)
        if (filter === '🏷️ Sale') list = list.filter(p => p.badge === 'Sale')
        if (filter === '✨ New') list = list.filter(p => p.badge === 'New')
        if (filter === '⭐ Popular') list = list.filter(p => p.rev > 10000)
        if (sort === 'price-low') list.sort((a, b) => a.price - b.price)
        if (sort === 'price-high') list.sort((a, b) => b.price - a.price)
        if (sort === 'rating') list.sort((a, b) => b.rating - a.rating)
        if (sort === 'reviews') list.sort((a, b) => b.rev - a.rev)
        return list
    }, [category, filter, sort, effectiveMax])

    const handleCompare = (p) => {
        if (compareList.find(x => x.id === p.id)) {
            setCompareList(c => c.filter(x => x.id !== p.id))
        } else if (compareList.length >= 3) {
            notify('Max 3 products to compare!', 'warning')
        } else {
            setCompareList(c => [...c, p]); notify(`${p.name} added to compare ⚖️`)
        }
    }

    if (!cat) return (
        <div className="p-20 text-center text-gray-500 dark:text-gray-400">
            <div className="text-5xl mb-4">😕</div>
            <p className="text-lg font-semibold mb-4">Category not found.</p>
            <Link to="/" className="btn-primary px-6 py-2 rounded-xl">← Go Home</Link>
        </div>
    )

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-gray-950 pb-24 md:pb-8">

            {/* Compact Page Header */}
            <div className="bg-white dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 px-4 py-4">
                <div className="max-w-7xl mx-auto flex items-center justify-between gap-4">
                    {/* Left: title */}
                    <h1 className="text-xl font-extrabold text-gray-900 dark:text-white flex items-center gap-2">
                        <span className="text-2xl">{cat.icon}</span>
                        {cat.name}
                        <span className="hidden sm:inline text-sm font-normal text-gray-400 ml-1">— {cat.desc}</span>
                    </h1>
                    {/* Right: filtered item count */}
                    <span className="text-sm text-gray-500 dark:text-gray-400 bg-gray-100 dark:bg-gray-800 px-3 py-1 rounded-full font-semibold whitespace-nowrap">
                        {filtered.length} of {catProducts.length} products
                    </span>
                </div>
            </div>

            <div className="max-w-7xl mx-auto px-4 py-6">
                {/* FILTER BAR — compact single row */}
                <div className="flex flex-wrap gap-2 items-center justify-between mb-6 bg-white dark:bg-gray-800 rounded-xl px-4 py-3 shadow-sm border border-gray-100 dark:border-gray-700">
                    {/* Filter pills */}
                    <div className="flex gap-1.5 flex-wrap">
                        {FILTERS.map(f => (
                            <button key={f} onClick={() => setFilter(f)}
                                className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all duration-200 ${filter === f ? 'bg-amber-400 text-gray-900' : 'bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 hover:bg-amber-50 dark:hover:bg-gray-600'}`}>
                                {f}
                            </button>
                        ))}
                    </div>

                    {/* Right controls */}
                    <div className="flex items-center gap-3 flex-wrap">
                        {/* Price range */}
                        <div className="flex items-center gap-2">
                            <span className="text-xs text-gray-400 whitespace-nowrap">Max:</span>
                            <input type="range" className="w-24 accent-amber-400" min={0} max={maxPrice} step={100}
                                value={effectiveMax} onChange={e => setPriceMax(Number(e.target.value))} />
                            <span className="text-xs font-bold text-amber-500 whitespace-nowrap min-w-[60px]">{formatPrice(effectiveMax)}</span>
                        </div>
                        {/* Sort */}
                        <select value={sort} onChange={e => setSort(e.target.value)}
                            className="px-2.5 py-1.5 rounded-lg border border-gray-200 dark:border-gray-600 bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-200 text-xs font-medium outline-none focus:border-amber-400">
                            {SORTS.map(s => <option key={s.value} value={s.value}>{s.label}</option>)}
                        </select>
                        <span className="text-xs text-gray-400">{filtered.length} items</span>
                    </div>
                </div>

                {/* PRODUCTS GRID */}
                {filtered.length === 0 ? (
                    <div className="text-center py-20 text-gray-400">
                        <div className="text-5xl mb-4">😕</div>
                        <p className="text-lg font-medium mb-4">No products match your filters.</p>
                        <button onClick={() => { setFilter('All'); setPriceMax(null) }} className="btn-primary px-6 py-2 rounded-lg text-sm">Reset Filters</button>
                    </div>
                ) : (
                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                        {filtered.map(p => (
                            <ProductCard key={p.id} product={p} onQuickView={setQuickProduct} showCompare onCompare={handleCompare} />
                        ))}
                    </div>
                )}
            </div>

            {/* Compare bar */}
            {compareList.length > 0 && (
                <div className="fixed bottom-16 md:bottom-0 left-0 right-0 bg-gray-900 text-white px-4 py-3 z-40 shadow-2xl border-t border-white/10">
                    <div className="max-w-7xl mx-auto flex items-center gap-3 flex-wrap">
                        <span className="text-sm font-bold text-amber-400 flex-shrink-0">⚖️ Compare</span>
                        <div className="flex gap-2 flex-1 flex-wrap">
                            {compareList.map(p => (
                                <div key={p.id} className="bg-white/10 rounded-lg px-3 py-1 flex items-center gap-2 text-sm">
                                    <span className="truncate max-w-[100px] font-medium">{p.name}</span>
                                    <button onClick={() => setCompareList(c => c.filter(x => x.id !== p.id))} className="text-white/60 hover:text-white">✕</button>
                                </div>
                            ))}
                        </div>
                        {compareList.length >= 2 && (
                            <Link to="/compare" onClick={() => localStorage.setItem('compareList', JSON.stringify(compareList))}
                                className="bg-amber-400 hover:bg-amber-500 text-gray-900 font-bold px-4 py-1.5 rounded-lg text-sm transition-colors">Compare →</Link>
                        )}
                        <button onClick={() => setCompareList([])} className="text-white/50 hover:text-white text-sm px-3 py-1.5 border border-white/20 rounded-lg">Clear</button>
                    </div>
                </div>
            )}

            {quickProduct && <QuickViewModal product={quickProduct} onClose={() => setQuickProduct(null)} />}
        </div>
    )
}

import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useCart } from '../context/CartContext'
import { useAuth } from '../context/AuthContext'
import { useNotification } from '../components/Notification'
import { useCurrency } from '../context/CurrencyContext'
import { db } from '../firebase/config'
import { addDoc, collection, serverTimestamp } from 'firebase/firestore'
import usePageTitle from '../hooks/usePageTitle'

const PAYMENT_METHODS = [
    { id: 'upi', label: 'UPI / Google Pay / PhonePe', icon: '📱' },
    { id: 'card', label: 'Credit / Debit Card', icon: '💳' },
    { id: 'net', label: 'Net Banking', icon: '🏦' },
    { id: 'cod', label: 'Cash on Delivery', icon: '💵' },
]

export default function Checkout() {
    usePageTitle('Checkout')
    const { cart, subtotal, shipping, tax, total, clearCart } = useCart()
    const { user } = useAuth()
    const { notify } = useNotification()
    const { formatPrice } = useCurrency()
    const navigate = useNavigate()

    const [step, setStep] = useState(1)   // 1=Shipping 2=Payment 3=Success
    const [payMethod, setPayMethod] = useState('upi')
    const [form, setForm] = useState({
        name: user?.name || '', email: user?.email || '',
        phone: '', address: '', city: '', state: '', pincode: ''
    })
    const [processing, setProcessing] = useState(false)

    // ── Place order immediately — no payment gateway ──
    const handleOrder = async () => {
        setProcessing(true)
        const order = {
            id: 'SS' + Date.now(),
            items: cart.map(i => ({ id: i.id, name: i.name, price: i.price, qty: i.qty, img: i.img })),
            total, shipping, tax, subtotal,
            address: form,
            paymentMethod: payMethod,
            userId: user?.uid || user?.email || 'guest',
            status: 'Confirmed',
        }

        try {
            // Save to Firestore if available, else localStorage
            if (db) {
                await addDoc(collection(db, 'orders'), { ...order, createdAt: serverTimestamp() })
            } else {
                const orders = JSON.parse(localStorage.getItem('orders') || '[]')
                orders.unshift({ ...order, createdAt: new Date().toISOString() })
                localStorage.setItem('orders', JSON.stringify(orders))
            }
        } catch (e) {
            // Firestore failed — save locally
            const orders = JSON.parse(localStorage.getItem('orders') || '[]')
            orders.unshift({ ...order, createdAt: new Date().toISOString() })
            localStorage.setItem('orders', JSON.stringify(orders))
        }

        clearCart()
        setProcessing(false)
        setStep(3)
    }

    const handleShippingNext = () => {
        if (!form.name || !form.email || !form.phone || !form.address || !form.city || !form.state || !form.pincode) {
            notify('Please fill all shipping fields', 'warning'); return
        }
        if (!/^\d{6}$/.test(form.pincode)) { notify('Enter a valid 6-digit pincode', 'warning'); return }
        if (!/^\d{10}$/.test(form.phone)) { notify('Enter a valid 10-digit phone number', 'warning'); return }
        setStep(2)
    }

    if (cart.length === 0 && step !== 3) { navigate('/cart'); return null }

    // ── SUCCESS SCREEN ──
    if (step === 3) return (
        <div className="min-h-screen flex items-center justify-center dark:bg-gray-950 p-8">
            <div className="max-w-lg w-full text-center">
                <div className="text-8xl mb-4 animate-bounce">🎉</div>
                <h1 className="text-4xl font-extrabold text-gray-900 dark:text-white mb-3">Order Placed!</h1>
                <p className="text-gray-500 dark:text-gray-400 text-lg mb-2">
                    Thank you, <span className="font-bold text-gray-800 dark:text-white">{form.name || user?.name || 'Customer'}</span>!
                </p>
                <p className="text-gray-400 mb-8">Your order is confirmed and will be delivered in 2–5 business days.</p>

                <div className="bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-2xl p-6 mb-6 text-left space-y-3">
                    <div className="flex justify-between items-center">
                        <span className="text-gray-500 text-sm">Order Total</span>
                        <span className="font-extrabold text-amber-500 text-xl">{formatPrice(total)}</span>
                    </div>
                    <div className="flex justify-between items-center">
                        <span className="text-gray-500 text-sm">Payment</span>
                        <span className="text-gray-700 dark:text-gray-300 text-sm font-semibold">
                            {PAYMENT_METHODS.find(m => m.id === payMethod)?.icon} {PAYMENT_METHODS.find(m => m.id === payMethod)?.label}
                        </span>
                    </div>
                    <div className="flex justify-between items-center">
                        <span className="text-gray-500 text-sm">Deliver to</span>
                        <span className="text-gray-700 dark:text-gray-300 text-sm font-semibold text-right max-w-[200px]">
                            {form.address}, {form.city}, {form.state} — {form.pincode}
                        </span>
                    </div>
                    <div className="flex justify-between items-center pt-1 border-t border-green-200 dark:border-green-800">
                        <span className="text-gray-500 text-sm">Status</span>
                        <span className="bg-green-100 text-green-700 dark:bg-green-900/40 dark:text-green-400 px-3 py-1 rounded-full text-xs font-bold">
                            ✅ Confirmed
                        </span>
                    </div>
                </div>

                <div className="flex gap-3 justify-center flex-wrap">
                    <button onClick={() => navigate('/')} className="btn-primary px-8 py-3 rounded-xl">
                        Continue Shopping 🛍️
                    </button>
                    <button onClick={() => navigate('/orders')} className="btn-outline px-8 py-3 rounded-xl">
                        View My Orders 📦
                    </button>
                </div>
            </div>
        </div>
    )

    return (
        <div className="min-h-screen dark:bg-gray-950 pb-24 md:pb-8">
            <div className="max-w-5xl mx-auto px-4 py-8">
                <h1 className="text-2xl font-extrabold text-gray-900 dark:text-white mb-6">Secure Checkout</h1>

                {/* Progress Steps */}
                <div className="flex items-center gap-2 mb-8 text-sm">
                    {['Shipping Info', 'Payment', 'Done'].map((s, i) => (
                        <div key={s} className="flex items-center gap-2">
                            <div className={`w-7 h-7 rounded-full flex items-center justify-center font-bold text-xs transition-colors ${step > i ? 'bg-green-500 text-white' : step === i + 1 ? 'bg-amber-400 text-gray-900' : 'bg-gray-200 dark:bg-gray-700 text-gray-500'}`}>
                                {step > i ? '✓' : i + 1}
                            </div>
                            <span className={step === i + 1 ? 'font-bold text-gray-900 dark:text-white' : 'text-gray-400 text-xs'}>
                                {s}
                            </span>
                            {i < 2 && <span className="text-gray-300 dark:text-gray-700 mx-1">—</span>}
                        </div>
                    ))}
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    {/* ── LEFT: Step forms ── */}
                    <div className="lg:col-span-2">

                        {/* Step 1: Shipping */}
                        {step === 1 && (
                            <div className="card p-6">
                                <h2 className="text-lg font-extrabold text-gray-900 dark:text-white mb-5">📦 Shipping Details</h2>
                                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                    {[
                                        ['Full Name', 'name', 'text'],
                                        ['Email', 'email', 'email'],
                                        ['Phone Number', 'phone', 'tel'],
                                        ['Full Address', 'address', 'text'],
                                    ].map(([label, key, type]) => (
                                        <div key={key} className={key === 'address' ? 'sm:col-span-2' : ''}>
                                            <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-1.5">{label}</label>
                                            <input type={type} value={form[key]}
                                                onChange={e => setForm(f => ({ ...f, [key]: e.target.value }))}
                                                className="input" placeholder={
                                                    key === 'phone' ? '10-digit mobile number' :
                                                        key === 'address' ? 'House no., Street, Area' : ''
                                                } />
                                        </div>
                                    ))}
                                    <div>
                                        <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-1.5">City</label>
                                        <input value={form.city} onChange={e => setForm(f => ({ ...f, city: e.target.value }))} className="input" placeholder="Mumbai" />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-1.5">State</label>
                                        <select value={form.state} onChange={e => setForm(f => ({ ...f, state: e.target.value }))} className="input">
                                            <option value="">Select State</option>
                                            {['Andhra Pradesh', 'Arunachal Pradesh', 'Assam', 'Bihar', 'Chhattisgarh', 'Delhi', 'Goa', 'Gujarat', 'Haryana', 'Himachal Pradesh', 'Jharkhand', 'Karnataka', 'Kerala', 'Madhya Pradesh', 'Maharashtra', 'Manipur', 'Meghalaya', 'Mizoram', 'Nagaland', 'Odisha', 'Punjab', 'Rajasthan', 'Sikkim', 'Tamil Nadu', 'Telangana', 'Tripura', 'Uttar Pradesh', 'Uttarakhand', 'West Bengal'].map(s => <option key={s}>{s}</option>)}
                                        </select>
                                    </div>
                                    <div>
                                        <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-1.5">Pincode</label>
                                        <input type="text" value={form.pincode}
                                            onChange={e => setForm(f => ({ ...f, pincode: e.target.value.replace(/\D/g, '').slice(0, 6) }))}
                                            className="input" maxLength={6} placeholder="6-digit pincode" />
                                    </div>
                                </div>
                                <button onClick={handleShippingNext}
                                    className="btn-primary w-full py-3.5 rounded-xl mt-6 text-base font-bold">
                                    Continue to Payment →
                                </button>
                            </div>
                        )}

                        {/* Step 2: Payment */}
                        {step === 2 && (
                            <div className="card p-6">
                                <h2 className="text-lg font-extrabold text-gray-900 dark:text-white mb-5">💳 Choose Payment Method</h2>
                                <div className="space-y-3 mb-6">
                                    {PAYMENT_METHODS.map(m => (
                                        <label key={m.id} className={`flex items-center gap-4 p-4 rounded-xl border-2 cursor-pointer transition-all ${payMethod === m.id ? 'border-amber-400 bg-amber-50 dark:bg-amber-900/20' : 'border-gray-200 dark:border-gray-700 hover:border-amber-300'}`}>
                                            <input type="radio" name="pay" value={m.id} checked={payMethod === m.id} onChange={() => setPayMethod(m.id)} className="accent-amber-400" />
                                            <span className="text-2xl">{m.icon}</span>
                                            <div>
                                                <p className="font-semibold text-gray-900 dark:text-white text-sm">{m.label}</p>
                                                {m.id === 'cod' && <p className="text-xs text-gray-400 mt-0.5">Pay when your order arrives</p>}
                                                {m.id === 'upi' && <p className="text-xs text-gray-400 mt-0.5">Instant payment via UPI apps</p>}
                                                {m.id === 'card' && <p className="text-xs text-gray-400 mt-0.5">Visa, Mastercard, RuPay accepted</p>}
                                                {m.id === 'net' && <p className="text-xs text-gray-400 mt-0.5">All major banks supported</p>}
                                            </div>
                                        </label>
                                    ))}
                                </div>

                                <div className="bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-xl px-4 py-3 mb-5 text-xs text-blue-600 dark:text-blue-400 flex items-center gap-2">
                                    🔒 Your order will be placed securely. Payment collected on delivery / via selected method.
                                </div>

                                <div className="flex gap-3">
                                    <button onClick={() => setStep(1)} className="btn-outline flex-1 py-3.5 rounded-xl font-semibold">← Back</button>
                                    <button onClick={handleOrder} disabled={processing}
                                        className="btn-primary flex-[2] py-3.5 rounded-xl text-base font-bold disabled:opacity-70">
                                        {processing
                                            ? <span className="flex items-center justify-center gap-2"><span className="animate-spin">⏳</span> Placing Order...</span>
                                            : `✅ Place Order · ${formatPrice(total)}`
                                        }
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* ── RIGHT: Order Summary ── */}
                    <div className="card p-5 h-fit sticky top-24">
                        <h3 className="font-extrabold text-gray-900 dark:text-white mb-4">
                            🛍️ Order Summary <span className="text-gray-400 text-sm font-normal">({cart.length} items)</span>
                        </h3>
                        <div className="space-y-3 mb-4 max-h-48 overflow-y-auto pr-1">
                            {cart.map(i => (
                                <div key={i.id} className="flex gap-3 items-center">
                                    <img src={i.img} alt={i.name} className="w-11 h-11 rounded-lg object-cover flex-shrink-0" onError={e => { e.target.style.display = 'none' }} />
                                    <div className="flex-1 min-w-0">
                                        <p className="text-xs font-semibold text-gray-800 dark:text-gray-200 truncate">{i.name}</p>
                                        <p className="text-xs text-gray-400">× {i.qty}</p>
                                    </div>
                                    <span className="text-xs font-bold text-amber-500 flex-shrink-0">{formatPrice(i.price * i.qty)}</span>
                                </div>
                            ))}
                        </div>
                        <div className="border-t border-gray-100 dark:border-gray-700 pt-3 space-y-2 text-sm">
                            <div className="flex justify-between text-gray-500"><span>Subtotal</span><span>{formatPrice(subtotal)}</span></div>
                            <div className="flex justify-between text-gray-500"><span>Shipping</span><span className={shipping === 0 ? 'text-green-500 font-bold' : ''}>{shipping === 0 ? 'FREE' : formatPrice(shipping)}</span></div>
                            <div className="flex justify-between text-gray-500"><span>GST (18%)</span><span>{formatPrice(tax)}</span></div>
                            <div className="flex justify-between font-extrabold text-gray-900 dark:text-white text-base pt-2 border-t border-gray-100 dark:border-gray-700">
                                <span>Total</span><span className="text-amber-500">{formatPrice(total)}</span>
                            </div>
                        </div>
                        {shipping === 0 && (
                            <p className="text-xs text-green-600 dark:text-green-400 mt-2 font-medium text-center">🎉 You qualify for FREE shipping!</p>
                        )}
                    </div>
                </div>
            </div>
        </div>
    )
}

import { useState } from 'react'
import { Link } from 'react-router-dom'
import HeroCarousel from '../components/HeroCarousel'
import FlashSaleTimer from '../components/FlashSaleTimer'
import ProductCard from '../components/ProductCard'
import QuickViewModal from '../components/QuickViewModal'
import NewsletterPopup from '../components/NewsletterPopup'
import { products, CATEGORY_META } from '../data/products'
import { useNotification } from '../components/Notification'
import { useCart } from '../context/CartContext'
import usePageTitle from '../hooks/usePageTitle'

const TABS = ['All', '⭐ Best Sellers', '✨ New Arrivals', '🏷️ On Sale']

export default function Home() {
    usePageTitle('Home — Best Deals on Electronics, Fashion & More')
    const [activeTab, setActiveTab] = useState('All')
    const [quickProduct, setQuickProduct] = useState(null)
    const [compareList, setCompareList] = useState([])
    const { notify } = useNotification()
    const { addToCart } = useCart()

    const getFiltered = () => {
        if (activeTab === '⭐ Best Sellers') return products.filter(p => p.badge === 'Best Seller').slice(0, 8)
        if (activeTab === '✨ New Arrivals') return products.filter(p => p.badge === 'New').slice(0, 8)
        if (activeTab === '🏷️ On Sale') return products.filter(p => p.badge === 'Sale').slice(0, 8)
        return products.slice(0, 8)
    }

    const handleCompare = (p) => {
        if (compareList.find(x => x.id === p.id)) {
            setCompareList(c => c.filter(x => x.id !== p.id))
        } else if (compareList.length >= 3) {
            notify('Max 3 products to compare!', 'warning')
        } else {
            setCompareList(c => [...c, p])
            notify(`${p.name} added to compare ⚖️`)
        }
    }

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-gray-950">
            {/* Flash Sale */}
            <FlashSaleTimer />

            {/* Hero Carousel */}
            <HeroCarousel />

            {/* Categories */}
            <section className="py-14 max-w-7xl mx-auto px-4">
                <h2 className="section-title">Shop by Category</h2>
                <p className="section-subtitle">Explore 6 categories with 50+ curated products</p>
                <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-6 gap-4">
                    {Object.entries(CATEGORY_META).map(([key, cat]) => (
                        <Link key={key} to={cat.path}
                            className="card flex flex-col items-center py-6 px-3 hover:border-amber-400 dark:hover:border-amber-400 text-center group hover:bg-amber-50 dark:hover:bg-amber-900/10 transition-all duration-300">
                            <span className="text-4xl mb-3 group-hover:scale-110 transition-transform duration-300">{cat.icon}</span>
                            <h3 className="font-bold text-sm text-gray-900 dark:text-white">{cat.name}</h3>
                            <p className="text-xs text-gray-400 mt-1">{cat.desc.split(',')[0]}</p>
                        </Link>
                    ))}
                </div>
            </section>

            {/* Featured Products with Tabs */}
            <section className="py-8 pb-16 max-w-7xl mx-auto px-4">
                <h2 className="section-title">Featured Products</h2>
                {/* Tabs */}
                <div className="flex justify-center mb-8">
                    <div className="flex bg-gray-100 dark:bg-gray-800 rounded-xl p-1.5 gap-1 flex-wrap justify-center">
                        {TABS.map(tab => (
                            <button key={tab} onClick={() => setActiveTab(tab)}
                                className={`px-5 py-2.5 rounded-lg text-sm font-semibold transition-all duration-200 ${activeTab === tab ? 'bg-amber-400 text-gray-900 shadow-md shadow-amber-200 dark:shadow-amber-900' : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white'}`}>
                                {tab}
                            </button>
                        ))}
                    </div>
                </div>
                {/* Grid */}
                <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
                    {getFiltered().map(p => (
                        <ProductCard key={p.id} product={p} onQuickView={setQuickProduct} showCompare onCompare={handleCompare} />
                    ))}
                </div>
                <div className="text-center mt-10">
                    <Link to="/electronics" className="btn-secondary inline-block rounded-xl px-8 py-4 text-base hover:-translate-y-1 transition-all">
                        Browse All Products →
                    </Link>
                </div>
            </section>

            {/* Compare Bar */}
            {compareList.length > 0 && (
                <div className="fixed bottom-0 md:bottom-0 left-0 right-0 bg-gray-900 text-white px-4 py-3 z-40 shadow-2xl animate-slide-up">
                    <div className="max-w-7xl mx-auto flex items-center gap-3 flex-wrap">
                        <div className="flex gap-2 flex-1 flex-wrap">
                            {compareList.map(p => (
                                <div key={p.id} className="bg-white/10 rounded-lg px-3 py-1.5 flex items-center gap-2 text-sm">
                                    <span className="font-medium truncate max-w-[140px]">{p.name}</span>
                                    <button onClick={() => setCompareList(c => c.filter(x => x.id !== p.id))} className="text-white/50 hover:text-white">✕</button>
                                </div>
                            ))}
                        </div>
                        {compareList.length >= 2 && (
                            <Link to="/compare" onClick={() => localStorage.setItem('compareList', JSON.stringify(compareList))}
                                className="bg-amber-400 text-gray-900 font-bold px-5 py-2 rounded-lg text-sm transition-colors hover:bg-amber-500">
                                ⚖️ Compare
                            </Link>
                        )}
                        <button onClick={() => setCompareList([])} className="border border-white/30 text-white/70 hover:text-white font-medium px-4 py-2 rounded-lg text-sm transition-colors">
                            Clear
                        </button>
                    </div>
                </div>
            )}

            {/* Quick View Modal */}
            {quickProduct && <QuickViewModal product={quickProduct} onClose={() => setQuickProduct(null)} />}

            {/* Newsletter Popup */}
            <NewsletterPopup />
        </div>
    )
}

import { useState, useEffect } from 'react'
import { Link } from 'react-router-dom'
import { formatPrice } from '../data/products'
import { db } from '../firebase/config'
import { collection, getDocs, query, where, orderBy } from 'firebase/firestore'
import { useAuth } from '../context/AuthContext'
import usePageTitle from '../hooks/usePageTitle'

const STATUS_STYLES = {
    Confirmed: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400',
    Processing: 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400',
    Shipped: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400',
    Delivered: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400',
    Cancelled: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400',
}

export default function Orders() {
    usePageTitle('My Orders')
    const { user } = useAuth()
    const [orders, setOrders] = useState([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const load = async () => {
            try {
                if (db && user?.uid) {
                    // Query by uid (primary) OR email (legacy orders)
                    const [snapUid, snapEmail] = await Promise.all([
                        getDocs(query(collection(db, 'orders'), where('userId', '==', user.uid))),
                        getDocs(query(collection(db, 'orders'), where('userId', '==', user.email))),
                    ])
                    const fromUid = snapUid.docs.map(d => ({ ...d.data(), _docId: d.id }))
                    const fromEmail = snapEmail.docs.map(d => ({ ...d.data(), _docId: d.id }))
                    // Merge + deduplicate by document id
                    const seen = new Set()
                    const merged = [...fromUid, ...fromEmail].filter(o => {
                        if (seen.has(o._docId)) return false
                        seen.add(o._docId); return true
                    })
                    // Sort newest first
                    merged.sort((a, b) => {
                        const ta = a.createdAt?.toMillis?.() || 0
                        const tb = b.createdAt?.toMillis?.() || 0
                        return tb - ta
                    })
                    setOrders(merged)
                } else {
                    // Fallback: localStorage
                    const local = JSON.parse(localStorage.getItem('orders') || '[]')
                    setOrders(local)
                }
            } catch (e) {
                console.warn('Orders fetch error:', e)
                const local = JSON.parse(localStorage.getItem('orders') || '[]')
                setOrders(local)
            }
            setLoading(false)
        }
        load()
    }, [user])

    if (loading) return (
        <div className="min-h-screen flex items-center justify-center dark:bg-gray-950">
            <div className="text-center">
                <div className="animate-spin w-12 h-12 border-4 border-amber-400 border-t-transparent rounded-full mx-auto mb-4" />
                <p className="text-gray-500 dark:text-gray-400">Loading your orders...</p>
            </div>
        </div>
    )

    return (
        <div className="min-h-screen dark:bg-gray-950 pb-24 md:pb-8">
            <div className="max-w-4xl mx-auto px-4 py-10">
                <div className="mb-8">
                    <h1 className="text-3xl font-extrabold text-gray-900 dark:text-white mb-1">📦 My Orders</h1>
                    <p className="text-gray-500 dark:text-gray-400">
                        {orders.length > 0 ? `${orders.length} order${orders.length > 1 ? 's' : ''} found` : 'Track and manage your orders'}
                    </p>
                </div>

                {orders.length === 0 ? (
                    <div className="text-center py-24">
                        <div className="text-7xl mb-5">📦</div>
                        <h2 className="text-2xl font-extrabold text-gray-700 dark:text-gray-200 mb-2">No orders yet</h2>
                        <p className="text-gray-400 mb-8">Your orders will appear here once you place one.</p>
                        <Link to="/" className="btn-primary px-10 py-3.5 rounded-xl text-base font-bold">
                            Start Shopping →
                        </Link>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {orders.map((order, idx) => {
                            const status = order.status || 'Confirmed'
                            const date = order.createdAt?.toDate?.()?.toLocaleDateString('en-IN', {
                                day: 'numeric', month: 'short', year: 'numeric'
                            }) || new Date().toLocaleDateString('en-IN')
                            const orderId = order.id || order._docId || ('SS' + (1001 + idx))

                            return (
                                <div key={order._docId || idx} className="card p-6">
                                    {/* Header */}
                                    <div className="flex justify-between items-start mb-5 flex-wrap gap-2">
                                        <div>
                                            <p className="font-extrabold text-gray-900 dark:text-white text-sm">
                                                Order <span className="text-amber-500">#{orderId}</span>
                                            </p>
                                            <p className="text-xs text-gray-400 mt-0.5">Placed on {date}</p>
                                        </div>
                                        <span className={`px-3 py-1 rounded-full text-xs font-bold ${STATUS_STYLES[status] || STATUS_STYLES.Confirmed}`}>
                                            {status === 'Confirmed' && '✅ '}{status}
                                        </span>
                                    </div>

                                    {/* Items */}
                                    <div className="space-y-3 mb-5">
                                        {(order.items || []).map((item, i) => (
                                            <div key={i} className="flex items-center gap-3">
                                                <img src={item.img} alt={item.name}
                                                    className="w-12 h-12 rounded-xl object-cover flex-shrink-0 bg-gray-100"
                                                    onError={e => { e.target.style.display = 'none' }} />
                                                <span className="flex-1 text-sm text-gray-700 dark:text-gray-300 font-medium truncate">
                                                    {item.name} <span className="text-gray-400">× {item.qty}</span>
                                                </span>
                                                <span className="text-sm font-bold text-amber-500 flex-shrink-0">
                                                    {formatPrice(item.price * item.qty)}
                                                </span>
                                            </div>
                                        ))}
                                    </div>

                                    {/* Footer */}
                                    <div className="flex justify-between items-center border-t border-gray-100 dark:border-gray-700 pt-4 flex-wrap gap-3">
                                        <div>
                                            <p className="text-xs text-gray-400">
                                                {order.address?.city && `📍 ${order.address.city}, ${order.address.state}`}
                                            </p>
                                            <p className="font-extrabold text-gray-900 dark:text-white mt-0.5">
                                                Total: <span className="text-amber-500">{formatPrice(order.total || 0)}</span>
                                            </p>
                                        </div>
                                        <button
                                            onClick={() => alert(`Order #${orderId}\nStatus: ${status}\nDelivery: ${order.address?.city || 'N/A'}\n\nEstimated delivery: 2-5 business days`)}
                                            className="btn-outline px-5 py-2 rounded-xl text-sm font-semibold">
                                            Track Order 📍
                                        </button>
                                    </div>
                                </div>
                            )
                        })}
                    </div>
                )}
            </div>
        </div>
    )
}

import { useState, useEffect } from 'react'
import { useParams, Link, useNavigate } from 'react-router-dom'
import { products, getDiscount, CATEGORY_META, toSlug } from '../data/products'
import { useCart } from '../context/CartContext'
import { useWishlist } from '../context/WishlistContext'
import { useNotification } from '../components/Notification'
import { useCurrency } from '../context/CurrencyContext'
import ProductCard from '../components/ProductCard'
import { db } from '../firebase/config'
import { collection, addDoc, getDocs, query, where, orderBy, serverTimestamp } from 'firebase/firestore'
import usePageTitle from '../hooks/usePageTitle'



function ReviewForm({ productId, onSubmit }) {
    const [rating, setRating] = useState(0)
    const [hover, setHover] = useState(0)
    const [name, setName] = useState('')
    const [text, setText] = useState('')
    const [msg, setMsg] = useState('')

    const submit = async () => {
        if (!rating || !name || !text) { setMsg('Please fill all fields and select a rating.'); return }
        const review = { name, text, rating, date: new Date().toLocaleDateString('en-IN') }
        onSubmit(review)
        setRating(0); setName(''); setText(''); setMsg('✅ Review submitted! Thank you.')
        setTimeout(() => setMsg(''), 3000)
    }

    return (
        <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-6 mb-6 shadow-sm">
            <h3 className="font-extrabold text-gray-900 dark:text-white text-lg mb-4">Write a Review</h3>
            <div className="flex gap-2 mb-4">
                {[1, 2, 3, 4, 5].map(n => (
                    <button key={n} onMouseEnter={() => setHover(n)} onMouseLeave={() => setHover(0)} onClick={() => setRating(n)}
                        className={`text-3xl transition-transform hover:scale-110 ${n <= (hover || rating) ? 'text-amber-400' : 'text-gray-300'}`}>★</button>
                ))}
            </div>
            <input type="text" value={name} onChange={e => setName(e.target.value)} placeholder="Your name" className="input mb-3" />
            <textarea value={text} onChange={e => setText(e.target.value)} placeholder="Share your thoughts about this product..." rows={3} className="input mb-3 resize-none" />
            <button onClick={submit} className="btn-primary w-full rounded-xl">Submit Review ✍️</button>
            {msg && <p className={`mt-2 text-sm font-medium ${msg.includes('✅') ? 'text-green-600' : 'text-red-500'}`}>{msg}</p>}
        </div>
    )
}

export default function Product() {
    const { slug } = useParams()
    const product = products.find(p => toSlug(p.name) === slug)
    usePageTitle(product ? product.name : 'Product Details')
    const navigate = useNavigate()
    const { addToCart } = useCart()
    const { toggleWishlist, isWishlisted } = useWishlist()
    const { notify } = useNotification()
    const { formatPrice } = useCurrency()
    const [mainImg, setMainImg] = useState(product?.img)
    const [qty, setQty] = useState(1)
    const [reviews, setReviews] = useState([])
    const [adding, setAdding] = useState(false)

    const relatedProducts = products.filter(p => p.cat === product?.cat && p.id !== product?.id).slice(0, 4)
    const disc = getDiscount(product?.price, product?.orig)
    const wished = isWishlisted(product?.id)

    useEffect(() => {
        if (!product) return
        setMainImg(product.img)
        const loadReviews = async () => {
            try {
                if (db) {
                    const q = query(collection(db, 'reviews'), where('productId', '==', product.id), orderBy('createdAt', 'desc'))
                    const snap = await getDocs(q)
                    const r = snap.docs.map(d => d.data())
                    setReviews(r.length ? r : defaultReviews())
                } else setReviews(JSON.parse(localStorage.getItem(`reviews_${product.id}`)) || defaultReviews())
            } catch { setReviews(defaultReviews()) }
        }
        loadReviews()
    }, [product?.id])

    const defaultReviews = () => ([
        { name: 'Priya Sharma', rating: 5, text: 'Absolutely love it! Great quality and fast delivery.', date: '15 Jan 2025' },
        { name: 'Rahul Mehta', rating: 4, text: 'Good product, exactly as described. Would recommend!', date: '10 Jan 2025' },
    ])

    const handleAddToCart = () => {
        if (!product) return
        setAdding(true)
        addToCart(product, qty)
        notify(`${product.name} added to cart! 🛒`)
        setTimeout(() => setAdding(false), 1000)
    }

    const handleReviewSubmit = async (review) => {
        const r = { ...review, productId: product.id }
        setReviews(prev => [review, ...prev])
        try {
            if (db) await addDoc(collection(db, 'reviews'), { ...r, createdAt: serverTimestamp() })
            else { const k = `reviews_${product.id}`; const prev = JSON.parse(localStorage.getItem(k) || '[]'); localStorage.setItem(k, JSON.stringify([r, ...prev])) }
        } catch (e) { console.warn(e) }
    }

    const copyLink = () => {
        navigator.clipboard.writeText(window.location.href)
        notify('Link copied! 🔗')
    }

    if (!product) return (
        <div className="min-h-screen flex items-center justify-center flex-col gap-4">
            <div className="text-6xl">😕</div>
            <p className="text-xl font-bold text-gray-700 dark:text-gray-300">Product not found</p>
            <Link to="/" className="btn-primary px-6 py-3 rounded-xl">← Back to Home</Link>
        </div>
    )

    const avgRating = reviews.length ? (reviews.reduce((s, r) => s + r.rating, 0) / reviews.length).toFixed(1) : product.rating

    return (
        <div className="min-h-screen dark:bg-gray-950 pb-24 md:pb-8">
            <div className="max-w-7xl mx-auto px-4 py-8">
                <nav className="text-sm text-gray-400 mb-6">
                    <Link to="/" className="hover:text-amber-500">Home</Link> /
                    <Link to={`/${product.cat}`} className="mx-1 hover:text-amber-500">{CATEGORY_META[product.cat]?.name}</Link> /
                    <span className="text-gray-600 dark:text-gray-300"> {product.name}</span>
                </nav>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 mb-16">
                    {/* GALLERY */}
                    <div>
                        <div className="rounded-2xl overflow-hidden mb-4 h-96 cursor-zoom-in group border border-gray-100 dark:border-gray-800">
                            <img src={mainImg} alt={product.name}
                                className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                                onError={e => { e.target.src = product.img; e.target.onerror = null }} />
                        </div>
                    </div>

                    {/* INFO PANEL */}
                    <div>
                        {product.badge && (
                            <span className={`badge mb-3 inline-block ${product.badge === 'Best Seller' ? 'bg-green-500 text-white' : product.badge === 'Sale' ? 'bg-red-500 text-white' : product.badge === 'Hot' ? 'bg-orange-500 text-white' : 'bg-blue-500 text-white'}`}>
                                {product.badge}
                            </span>
                        )}
                        <h1 className="text-2xl md:text-3xl font-extrabold text-gray-900 dark:text-white mb-3 leading-tight">{product.name}</h1>

                        {/* Rating */}
                        <div className="flex items-center gap-2 mb-4">
                            <span className="text-amber-400 text-xl">{'★'.repeat(Math.floor(avgRating))}{'☆'.repeat(5 - Math.floor(avgRating))}</span>
                            <span className="font-bold text-gray-700 dark:text-gray-300">{avgRating}</span>
                            <span className="text-gray-400 text-sm">({product.rev.toLocaleString('en-IN')} reviews)</span>
                        </div>

                        {/* Price */}
                        <div className="flex items-center gap-3 mb-5">
                            <span className="text-3xl font-extrabold text-amber-500">{formatPrice(product.price)}</span>
                            {product.orig > product.price && <>
                                <span className="text-lg text-gray-400 line-through">{formatPrice(product.orig)}</span>
                                <span className="bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400 text-sm font-bold px-2 py-1 rounded-lg">{disc}% OFF</span>
                            </>}
                        </div>

                        <p className="text-gray-600 dark:text-gray-400 leading-relaxed mb-6">{product.desc}</p>


                        {/* Qty */}
                        <div className="mb-6">
                            <p className="font-semibold text-sm text-gray-700 dark:text-gray-300 mb-2">Quantity:</p>
                            <div className="flex items-center gap-3">
                                <button onClick={() => setQty(q => Math.max(1, q - 1))} className="w-10 h-10 rounded-lg bg-gray-100 dark:bg-gray-700 font-bold text-lg hover:bg-amber-100 transition-colors">-</button>
                                <span className="w-10 text-center font-bold text-lg">{qty}</span>
                                <button onClick={() => setQty(q => Math.min(10, q + 1))} className="w-10 h-10 rounded-lg bg-gray-100 dark:bg-gray-700 font-bold text-lg hover:bg-amber-100 transition-colors">+</button>
                            </div>
                        </div>

                        {/* Action buttons */}
                        <div className="flex gap-3 mb-4 flex-wrap">
                            <button onClick={handleAddToCart}
                                className={`flex-1 py-4 rounded-xl font-bold text-base transition-all duration-200 ${adding ? 'bg-green-500 text-white' : 'bg-amber-400 hover:bg-amber-500 text-gray-900 hover:shadow-xl hover:-translate-y-1'}`}>
                                {adding ? '✓ Added to Cart!' : '🛒 Add to Cart'}
                            </button>
                            <button onClick={() => { addToCart(product, qty); navigate('/checkout') }}
                                className="flex-1 btn-secondary py-4 rounded-xl text-base">⚡ Buy Now</button>
                            <button onClick={() => { toggleWishlist(product); notify(wished ? 'Removed from wishlist' : 'Saved! ❤️', wished ? 'warning' : 'success') }}
                                className={`w-14 h-14 rounded-xl border-2 flex items-center justify-center text-xl transition-all ${wished ? 'border-red-400 bg-red-50 dark:bg-red-900/20 text-red-500' : 'border-gray-200 dark:border-gray-600 hover:border-red-400'}`}>
                                ♥
                            </button>
                        </div>

                        {/* Share */}
                        <div className="border-t border-gray-100 dark:border-gray-700 pt-4">
                            <p className="text-sm font-semibold text-gray-600 dark:text-gray-400 mb-2">📤 Share:</p>
                            <div className="flex gap-2 flex-wrap">
                                <button onClick={() => window.open(`https://wa.me/?text=Check out ${product.name} on Shop Smart! ${window.location.href}`, '_blank')}
                                    className="px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-600 text-sm font-medium hover:bg-green-50 hover:border-green-400 hover:text-green-600 transition-all dark:hover:bg-green-900/20">📱 WhatsApp</button>
                                <button onClick={() => window.open(`https://twitter.com/intent/tweet?text=${product.name}&url=${window.location.href}`, '_blank')}
                                    className="px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-600 text-sm font-medium hover:bg-blue-50 hover:border-blue-400 hover:text-blue-600 transition-all dark:hover:bg-blue-900/20">🐦 Twitter</button>
                                <button onClick={copyLink}
                                    className="px-3 py-2 rounded-lg border border-gray-200 dark:border-gray-600 text-sm font-medium hover:bg-amber-50 hover:border-amber-400 hover:text-amber-600 transition-all dark:hover:bg-amber-900/20">🔗 Copy</button>
                            </div>
                        </div>
                    </div>
                </div>

                {/* ALSO BOUGHT */}
                {relatedProducts.length > 0 && (
                    <section className="mb-16">
                        <h2 className="section-title text-left text-2xl mb-6">🛍️ Customers Also Bought</h2>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-5">
                            {relatedProducts.map(p => <ProductCard key={p.id} product={p} />)}
                        </div>
                    </section>
                )}

                {/* REVIEWS */}
                <section>
                    <h2 className="section-title text-left text-2xl mb-8">⭐ Customer Reviews</h2>
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                        {/* Overview */}
                        <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-6 shadow-sm text-center h-fit">
                            <div className="text-7xl font-black text-amber-500 leading-none">{avgRating}</div>
                            <div className="text-3xl text-amber-400 my-2">{'★'.repeat(Math.floor(avgRating))}{'☆'.repeat(5 - Math.floor(avgRating))}</div>
                            <p className="text-sm text-gray-400">Based on {reviews.length} review{reviews.length !== 1 ? 's' : ''}</p>
                            <div className="mt-5 space-y-2 text-left">
                                {[5, 4, 3, 2, 1].map(n => {
                                    const count = reviews.filter(r => r.rating === n).length
                                    const pct = reviews.length ? Math.round(count / reviews.length * 100) : 0
                                    return (
                                        <div key={n} className="flex items-center gap-2 text-sm">
                                            <span className="text-gray-500 w-5 text-right">{n}★</span>
                                            <div className="flex-1 h-2 bg-gray-100 dark:bg-gray-700 rounded-full overflow-hidden">
                                                <div className="h-full bg-amber-400 rounded-full transition-all duration-700" style={{ width: `${pct}%` }} />
                                            </div>
                                            <span className="text-gray-400 w-8 text-right">{pct}%</span>
                                        </div>
                                    )
                                })}
                            </div>
                        </div>

                        {/* Reviews list + form */}
                        <div className="lg:col-span-2">
                            <ReviewForm productId={product.id} onSubmit={handleReviewSubmit} />
                            <div className="space-y-4">
                                {reviews.slice(0, 5).map((r, i) => (
                                    <div key={i} className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-5 shadow-sm">
                                        <div className="flex justify-between mb-2">
                                            <div>
                                                <p className="font-bold text-gray-900 dark:text-white">{r.name}</p>
                                                <p className="text-xs text-gray-400">{r.date}</p>
                                            </div>
                                            <span className="text-amber-400">{'★'.repeat(r.rating)}{'☆'.repeat(5 - r.rating)}</span>
                                        </div>
                                        <p className="text-gray-600 dark:text-gray-400 text-sm leading-relaxed">{r.text}</p>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </section>
            </div>
        </div>
    )
}

/** @type {import('tailwindcss').Config} */
export default {
  content: ['./index.html', './src/**/*.{js,jsx,ts,tsx}'],
  darkMode: 'class',
  theme: {
    extend: {
      fontFamily: {
        inter: ['Inter', 'sans-serif'],
      },
      colors: {
        brand: {
          orange: '#ff9900',
          'orange-d': '#e68900',
          navy: '#232f3e',
          'navy-d': '#131921',
        },
      },
      animation: {
        'grad-shift': 'gradShift 9s ease infinite',
        'slide-up': 'slideUp 0.3s ease',
        'fade-in': 'fadeIn 0.2s ease',
        'blink': 'blink 1s infinite',
      },
      keyframes: {
        gradShift: {
          '0%,100%': { backgroundPosition: '0% 50%' },
          '50%': { backgroundPosition: '100% 50%' },
        },
        slideUp: {
          from: { transform: 'translateY(30px)', opacity: 0 },
          to: { transform: 'translateY(0)', opacity: 1 },
        },
        fadeIn: {
          from: { opacity: 0 },
          to: { opacity: 1 },
        },
        blink: {
          '0%,100%': { opacity: 0.7 },
          '50%': { opacity: 0.2 },
        },
      },
    },
  },
  plugins: [require('@tailwindcss/forms')],
}
